const snapRaw = $('Get Snapshot').first().json;
const abRaw = $('Get AB Stats').first().json;
const snap = snapRaw.data || snapRaw;
const risk = snap.risk || {};
const funnel = snap.funnel || {};
const pendingPct = ((risk.pendingRatio || 0) * 100).toFixed(1);
const riskScore = risk.score || 0;
const riskAction = risk.action || 'NORMAL';
const totalLeads = funnel.totalLeads || 0;
const invited = funnel.invited || 0;
const accepted = funnel.accepted || 0;
const replied = funnel.replied || 0;
const acceptanceRate = invited > 0 ? ((accepted / invited) * 100).toFixed(1) : '0.0';
const replyRate = accepted > 0 ? ((replied / accepted) * 100).toFixed(1) : '0.0';
const abStats = abRaw.data || abRaw || {};
const abVariants = JSON.stringify(abStats).slice(0, 500);
const monthDate = new Date().toISOString().slice(0, 7);
const prompt = 'Sei un analista di lead scoring per LinkedIn automation. Revisione mensile al ' + monthDate + '.\n\nMETRICHE MESE:\n- Funnel: ' + totalLeads + ' leads | ' + invited + ' invitati | ' + accepted + ' accettati | ' + replied + ' risposte\n- Acceptance rate: ' + acceptanceRate + '% | Reply rate: ' + replyRate + '%\n- Pending ratio: ' + pendingPct + '% (soglia critica: 65%)\n- Risk: ' + riskAction + ' (score ' + riskScore + '/100)\n- A/B test stats: ' + abVariants + '\n\nAnalizza se i criteri di scoring dei lead sono ancora validi e suggerisci modifiche per migliorare acceptance rate (obiettivo >30%), ridurre pending ratio (obiettivo <50%), aumentare reply rate. Output in italiano, max 15 righe:\n\n📋 *Analisi attuale*\n[2-3 bullet su cosa funziona/non funziona]\n\n🎯 *Parametri da modificare*\n| Parametro | Direzione | Motivazione |\n[tabella markdown 3-5 righe]\n\n🚦 *Priorità di intervento*\n[ordinati da urgente a facoltativo]';
const claudeBody = JSON.stringify({ model: 'claude-sonnet-4-6', max_tokens: 700, messages: [{ role: 'user', content: prompt }] });
return [{ json: { claudeBody, monthDate, acceptanceRate, replyRate, pendingPct, riskScore } }];

const response = $input.first().json;
const meta = $('Prepara Prompt').first().json;
let recalText = 'Analisi non disponibile — errore Claude.';
try {
  const text = response.content?.[0]?.text || '';
  if (text.length > 10) recalText = text;
} catch(e) {}
return [{ json: { recalText, monthDate: meta.monthDate } }];
